function createBaseProduct(options = {}) {
  const {
    id,
    name,
    brand,
    category,
    price,
    rating,
    image,
    description,
    highlights,
    drawbacks,
    compatibility,
    recommendedComponents,
    specs,
    ...rest
  } = options;

  return {
    id,
    name,
    brand,
    category,
    price,
    rating,
    image,
    description,
    highlights: highlights || [],
    drawbacks: drawbacks || [],
    compatibility: compatibility || 'Tương thích tốt với các mainboard, RAM và PSU ở cùng phân khúc.',
    recommendedComponents: recommendedComponents || [],
    specs: specs || {},
    ...rest
  };
}

function createCpuProduct(options) {
  return createBaseProduct({
    ...options,
    specs: {
      series: options.series,
      socket: options.socket,
      cores: options.cores,
      threads: options.threads,
      baseClock: options.baseClock,
      turboBoost: options.turboBoost,
      cache: options.cache,
      tdp: options.tdp,
      process: options.process,
      integratedGpu: options.integratedGpu,
      supportedRam: options.supportedRam,
      supportedPcie: options.supportedPcie,
      releaseDate: options.releaseDate,
      warranty: options.warranty
    }
  });
}

